INSERT INTO sadrzaj_predmeta (predmet_id, cilj, ishodi_ucenja, metode_nastave, teme_kursa) SELECT p.id, 'Cilj: usvojiti ključne koncepte modula kroz vežbe i ispit.', 'Ishodi: primena znanja u projektnim zadacima.', 'Predavanja, vežbe, laboratorija, ispit.', 'Teme: generisan demo sadržaj za NAIS prototip.' FROM predmet p WHERE p.sifra LIKE 'X%' AND NOT EXISTS (SELECT 1 FROM sadrzaj_predmeta s WHERE s.predmet_id = p.id);
INSERT INTO ispitni_termin (ispitni_rok_id, predmet_id, datum_vreme, sala) SELECT r.rok_id, p.id, r.dt, r.sala FROM predmet p CROSS JOIN LATERAL (VALUES (9,  timestamptz '2023-01-11 09:00:00+01', 'A-01'), (10, timestamptz '2023-06-12 09:00:00+02', 'A-02'), (11, timestamptz '2024-01-18 09:00:00+01', 'B-01'), (12, timestamptz '2024-06-20 09:00:00+02', 'B-02'), (13, timestamptz '2025-01-15 09:00:00+01', 'C-01'), (14, timestamptz '2025-06-22 09:00:00+02', 'C-02'), (15, timestamptz '2026-01-14 09:00:00+01', 'D-01'), (16, timestamptz '2026-06-18 09:00:00+02', 'D-02') ) AS r(rok_id, dt, sala) WHERE NOT EXISTS ( SELECT 1 FROM ispitni_termin ex WHERE ex.predmet_id = p.id AND ex.ispitni_rok_id = r.rok_id AND ex.datum_vreme = r.dt);
