((SELECT id FROM korisnik WHERE email = 'demo26_tk_2025_042@ftn.rs'), 'TK Z0042/25', 6, 2025)) AS v(kid, indeks, prog, y) WHERE kid IS NOT NULL ON CONFLICT (broj_indeksa) DO NOTHING;
INSERT INTO ocena (student_id, ispitni_termin_id, poeni, vrednost_ocene) SELECT q.student_id, q.ispitni_termin_id, q.poeni, q.vrednost_ocene FROM (   SELECT DISTINCT ON (s.id, it.id) s.id AS student_id, it.id AS ispitni_termin_id,     (18 + (abs(hashtext(concat_ws(':', s.id, it.id, 'p')))::bigint % 55))::int AS poeni,     CASE WHEN (abs(hashtext(concat_ws('g', s.id, it.predmet_id))) % 100) <       (38 + (abs(hashtext(it.predmet_id::text)) % 45))       THEN 6 + (abs(hashtext(concat_ws('z', s.id, it.id))) % 5) ELSE 5 END AS vrednost_ocene   FROM student s   JOIN allowed_demo_linear a ON a.program_id = s.studijski_program_id     AND a.godina_upisa = s.godina_upisa   JOIN predmet pr ON pr.studijski_program_id = s.studijski_program_id     AND pr.sifra = a.predmet_sifra   JOIN ispitni_termin it ON it.predmet_id = pr.id   JOIN ispitni_rok ir ON ir.id = it.ispitni_rok_id   JOIN korisnik ku ON ku.id = s.korisnik_id AND ku.email LIKE 'demo26_%@ftn.rs'   WHERE split_part(ir.skolska_godina, '/', 1)::int >= s.godina_upisa     AND split_part(ir.skolska_godina, '/', 1)::int <= 2025     AND nais_ocena_je_u_redu(s.godina_upisa, it.datum_vreme, pr.kurikulum_godina, pr.kurikulum_semestar)     AND (abs(hashtext(concat_ws('t', s.id, it.predmet_id, it.ispitni_rok_id))) % 10) < 7 ) q WHERE NOT EXISTS (   SELECT 1 FROM ocena o WHERE o.student_id = q.student_id   AND o.ispitni_termin_id = q.ispitni_termin_id);
INSERT INTO ocena (student_id, ispitni_termin_id, poeni, vrednost_ocene) SELECT q.student_id, it2.id, q.poeni2, q.oc2 FROM (   SELECT o.student_id, it.predmet_id, s.studijski_program_id, s.godina_upisa,     (22 + (abs(hashtext(concat_ws('r', o.student_id, it.predmet_id))) % 50))::int AS poeni2,     CASE WHEN (abs(hashtext(concat_ws('q', o.student_id, it.predmet_id, 'retry'))) % 100) < 55       THEN 6 + (abs(hashtext(concat_ws('v', o.student_id, min(it.id)::text))) % 5) ELSE 5 END AS oc2,     min(it.id) AS first_tid   FROM ocena o JOIN ispitni_termin it ON o.ispitni_termin_id = it.id   JOIN student s ON s.id = o.student_id   JOIN korisnik ku ON ku.id = s.korisnik_id AND ku.email LIKE 'demo26_%@ftn.rs'   WHERE o.vrednost_ocene = 5     AND (abs(hashtext(concat_ws('m', o.student_id, it.predmet_id))) % 100) < 62   GROUP BY o.student_id, it.predmet_id, s.studijski_program_id, s.godina_upisa ) q JOIN predmet pr ON pr.id = q.predmet_id JOIN allowed_demo_linear a ON a.program_id = q.studijski_program_id   AND a.godina_upisa = q.godina_upisa AND a.predmet_sifra = pr.sifra JOIN ispitni_termin it2 ON it2.predmet_id = q.predmet_id AND it2.id > q.first_tid JOIN ispitni_rok ir2 ON ir2.id = it2.ispitni_rok_id WHERE split_part(ir2.skolska_godina, '/', 1)::int >= q.godina_upisa   AND split_part(ir2.skolska_godina, '/', 1)::int <= 2025   AND nais_ocena_je_u_redu(q.godina_upisa, it2.datum_vreme, pr.kurikulum_godina, pr.kurikulum_semestar) AND NOT EXISTS (SELECT 1 FROM ocena o2 WHERE o2.student_id = q.student_id   AND o2.ispitni_termin_id = it2.id) AND it2.id = (SELECT t.id FROM ispitni_termin t   JOIN ispitni_rok irx ON irx.id = t.ispitni_rok_id   WHERE t.predmet_id = q.predmet_id AND t.id > q.first_tid     AND split_part(irx.skolska_godina, '/', 1)::int >= q.godina_upisa     AND split_part(irx.skolska_godina, '/', 1)::int <= 2025   ORDER BY t.datum_vreme ASC LIMIT 1);
